contract PostingBoard {
    struct Post {
        address author;
        bytes32 contentHash; // Use a hash to store content more efficiently
        uint256 totalPower;
    }

    mapping(uint256 => Post) private posts;
    mapping(address => uint256) private authorBalances;
    uint256 public postCount;

    event PostCreated(uint256 indexed postId, address indexed author, bytes32 contentHash);
    event PostBoosted(uint256 indexed postId, uint256 amount);
    event Withdrawal(address indexed author, uint256 amount);

    modifier nonReentrant() {
        require(_reentrancyGuard == false, "ReentrancyGuard: reentrant call");
        _reentrancyGuard = true;
        _;
        _reentrancyGuard = false;
    }

    bool private _reentrancyGuard = false;

    function getPost(uint256 postId) public view returns (address author, bytes32 contentHash, uint256 totalPower) {
        Post memory post = posts[postId];
        return (post.author, post.contentHash, post.totalPower);
    }

    function createPost(string memory content) public returns (uint256) {
        require(bytes(content).length > 0, "Content cannot be empty");
        uint256 newPostId = postCount++;
        posts[newPostId] = Post({
            author: msg.sender,
            contentHash: keccak256(abi.encodePacked(content)), // Store content hash instead of full string
            totalPower: 0
        });
        emit PostCreated(newPostId, msg.sender, posts[newPostId].contentHash);
        return newPostId;
    }

    function boostPost(uint256 postId) public payable {
        require(postId < postCount, "Post does not exist");
        require(msg.value > 0, "Boost amount must be greater than zero");
        Post storage post = posts[postId];
        require(post.author != address(0), "Invalid post");

        post.totalPower += msg.value;
        authorBalances[post.author] += msg.value;
        emit PostBoosted(postId, msg.value);
    }

    function authorBalances(address author) public view returns (uint256) {
        return authorBalances[author];
    }

    function withdraw() public nonReentrant {
        uint256 balance = authorBalances[msg.sender];
        require(balance > 0, "No balance to withdraw");
        authorBalances[msg.sender] = 0;
        require(payable(msg.sender).call{value: balance}(""), "Transfer failed");
        emit Withdrawal(msg.sender, balance);
    }
}
